import { useState } from "react";
import { AsyncPaginate } from "react-select-async-paginate";
import { GEO_API_URL, geoApiOptions } from "../../api";

const Search = ({ onSearchChange }) => {

    const [search, setSearch] = useState(null);

    const loadOptions = (searchInputValue) => {
      // Update the headers in each request to include the RapidAPI key and host
      const options = {
        ...geoApiOptions,
        headers: {
          ...geoApiOptions.headers,
          'X-RapidAPI-Key': '286073bc7dmshb52c71751250054p101f59jsn157d47486eb2',
          'X-RapidAPI-Host': 'wft-geo-db.p.rapidapi.com'
        }
      };

      return fetch(
        `${GEO_API_URL}/cities?minPopulation=1000000&namePrefix=${searchInputValue}`,
        options
      )
        .then((response) => {
          if (!response.ok) {
            throw new Error(`Failed to fetch data. Status: ${response.status}`);
          }
          return response.json();
        })
        .then((data) => {
          if (!data || !data.data || !Array.isArray(data.data)) {
            throw new Error("Invalid response format from the API");
          }

          const options = data.data.map((city) => ({
            value: `${city.latitude} ${city.longitude}`,
            label: `${city.name} ${city.countryCode}`,
          }));

          return { options };
        })
        .catch((error) => {
          console.error("Error fetching data:", error);
          // Return an empty options array in case of an error
          return { options: [] };
        });
    };



    const handleOnChange = (searchData) => {
        setSearch(searchData);
        onSearchChange(searchData);
    }

    return (<AsyncPaginate 
        placeholder = "Search for city"
        debounceTimeout={600}
        value={search}
        onChange = {handleOnChange}
        loadOptions = {loadOptions}
        />);
}

export default Search;
